var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"소녀는 먼 숲에서 나무 앞에 쓰러진 나무꾼을 발견했습니다.","JPN":"少女は森の奥で木の根元に倒れている木こりを\\n見つけました。","ENG":"The girl found the woodcutter in a faraway forest, lying in front of a tree.","TWN":"少女看到樵夫倒在遠處樹林中的一棵樹下。"},"stage":{"bg":"EV_SIGMA_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"나무꾼은 소녀가 아무리 불러도 깨어나지 않았어요.","JPN":"少女がいくら名前を呼んでも、木こりが目覚めることは\\nありませんでした。","ENG":"He wouldn't wake up, no matter how loudly she called him.","TWN":"少女不斷呼喚，但樵夫依舊沒有醒來。"},"stage":{"bg":"EV_SIGMA_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"마치 대답하지 못하는 딱딱한 인형처럼 말입니다.","JPN":"まるで、話すことができない堅い木のお人形のようでした。","ENG":"It was as if he'd turned into a wooden doll that couldn't talk.","TWN":"就像變成了一個不會說話的人偶。"},"stage":{"bg":"EV_SIGMA_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"나무꾼을 업어 집으로 돌아온 소녀는 나무꾼이 어떻게 하면 깨어날까 고민했습니다.","JPN":"木こりをおぶって家に帰ってきた少女は、どうすれば\\n木こりが目を覚ましてくれるのか考えました。","ENG":"The girl came back home with him on her back, and thought about how to wake him up.","TWN":"背著樵夫回家的少女想著，怎樣才能讓樵夫醒過來。"},"stage":{"bg":"EV_SIGMA_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"그러던 중 나무꾼이 해주던 요정의 이야기가 떠올랐어요.","JPN":"考えているうちに、木こりが聞かせてくれた妖精の\\n物語を思い出しました。","ENG":"Then, she remembered the fairy that he told her about.","TWN":"她想起了樵夫給她講過的妖精的故事。"},"stage":{"bg":"EV_SIGMA_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"자신이 요정을 만나서 나무꾼처럼 소원을 빌면......","JPN":"自分が妖精に会って木こりのようにお願いをすれば……","ENG":"Maybe she could plead with this fairy...","TWN":"如果自己去找妖精許願……"},"stage":{"bg":"EV_SIGMA_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"한때 인형이었던 자신이 그랬듯, 나무꾼도 다시 깨어날 수 있을 것이라 생각했습니다.","JPN":"かつて人形の自分がそうだったように、木こりも\\n目を覚ますことができると考えました。","ENG":"to bring him back, just like he did to give her life.","TWN":"或許就像自己從人偶變成人一樣，樵夫也能再次醒來。"},"stage":{"bg":"EV_SIGMA_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 소녀는 어디에 있는지도 모를 요정을 찾기 위해 다시 길을 떠났습니다.","JPN":"少女は居場所もわからない妖精を探し出すため、\\nさっそく旅に出ました。","ENG":"So, the girl set off on another journey to find this fairy, even though she didn't know where to find it.","TWN":"於是少女開始了尋找妖精的旅程。"},"stage":{"bg":"EV_SIGMA_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEE_FRONTIER_NULL_NULL","text":{"KOREA":"자, 다음!","JPN":"さあ、次！","ENG":"Alright, next!","TWN":"好，下一個！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PIRATE_FOX_MONITOR_NULL","text":{"KOREA":"큭...... 저 폭탄마 꼬맹이는 대체 뭐야! 로켓탄이 끝도 없이 튀어나오잖아!","JPN":"くっ……あの爆弾魔のチビは何なんだ！\\nロケット弾をとめどなく撃ち込んでくるじゃないか。","ENG":"Ugh... Where did that little crazy bomber come from? She's got an endless supply of rockets!","TWN":"咳……那個小鬼是怎麼回事！這火箭彈怎麼沒完沒了了！"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"MAYA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PIRATE_FOX_DIVER_NULL","text":{"KOREA":"뒤로 빠져나가려고 해도 두 녀석이 길을 막고 있어서 방법이 없어!","JPN":"後方に抜けようにも、あいつらが道を塞いでるから\\nどうしようもないぜ！","ENG":"We can't even fall back. Two of them are blocking the way.","TWN":"後面也被兩個人擋住了，根本沒辦法逃跑！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NINA_FRONTIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PIRATE_FOX_MONITOR_NULL","text":{"KOREA":"너, 너희들! 우리가 누구 밑에서 일하고 있는지는 알고서 이런 짓을 벌이는 거냐?","JPN":"お、お前ら！　俺らが誰の下で働いているかを\\n知った上でこんな無茶をしてるのか！？","ENG":"Y-you brats! Do you even know whom we are working for?","TWN":"你、你們！你們知道我們的頭是什麼人嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PIRATE_FOX_MONITOR_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PIRATE_FOX_DIVER_NULL","text":{"KOREA":"찰거머리 해적단의 기계수집가를 들어본 적이 없다곤 하지 않겠지?","JPN":"粘着海賊団の機械収集家って聞いたことあるだろ？","ENG":"You know who the Machine Collector of the Leech Pirates is, don't you?","TWN":"你們應該聽說過血蛭海盜團的機械收藏家吧？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"PIRATE_FOX_MONITOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEE_FRONTIER_NULL_NULL","text":{"KOREA":"......기계수집가?","JPN":"……機械収集家？","ENG":"The Machine Collector?","TWN":"……機械收藏家？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"LEE_FRONTIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PIRATE_FOX_DIVER_NULL","text":{"KOREA":"크큭, 그래. 그 분은 이세상 모든 기계를 자기 것으로 만드실 수 있는 분이지.","JPN":"ククッ、そうだ。あの方はこの世のあらゆる機械を\\n自分のモノにすることができる方なんだ。","ENG":"Heh he, that's right! She has the ability to make every machine in the world hers.","TWN":"嘿嘿，沒錯。那位能把全世界所有機械都能占為己有。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PIRATE_FOX_DIVER_NULL","text":{"KOREA":"그 분께서 손가락 하나만 튕기면 네 기계의수가 널 두들겨 패게 하실 수 있다고.","JPN":"あの方がその気になれば、おめえのその義手で\\nおめえ自身を攻撃させることなんてお手の物だ。","ENG":"She can make your machine arm beat you up with a simple flick of her fingers.","TWN":"只要他動一根手指，就能讓你的機械假肢痛扁你。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_DIVER_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};